css:
:root {
  /* blue accents all over (only rgb values) */
  --accent-color: 191 45 50;

  /* settings toggles (only rgb values) */
  --color-green: 175 85 37;
}

@font-face {
    font-family: 'Trajan Pro';
    font-style: normal;
    font-weight: 400;
    src: local('Trajan Pro'), url('https://fonts.cdnfonts.com/s/14928/TrajanPro-Regular.woff') format('woff');
    /* this fixes txhe bad baseline*/
    ascent-override: 110%;
}

@font-face {
    font-family: 'Trajan Pro';
    font-style: bold;
    font-weight: 700;
    src: local('Trajan Pro'), url('https://fonts.cdnfonts.com/s/14928/TrajanPro-Bold.woff') format('woff');
}

@font-face {
    font-family: 'Perpetua';
    font-style: normal;
    font-weight: 400;
    src: local('Perpetua'), url('https://cdn.wikimg.net/en/hkwiki/images/7/74/Perpetua.TTF') format('truetype');
}

#interface, #pomodoro_container.clone {
	font-family: Trajan Pro;
}

#quotes_container, #notes_container, #linkblocks, #contextmenu, #weather #description {
	font-family: Perpetua;
}

dialog#contextmenu {
    padding: 10px;
    background-color: #000000d1;
}

#contextmenu button {
	font-size: 1.1em;
    border-radius: 1px;
}

/* custom settings icon */
#show-settings svg {
  background-image: url("https://i.imgur.com/n6C8rGA.png");
  background-repeat: no-repeat;
  background-position: center;
  background-size: contain;
}

#show-settings svg * {
  display: none;
}

/* fleur for time */
.digital:after {
	content: '';
	background: url(https://i.imgur.com/pjF5HP7.png) center/contain no-repeat;
    display: block;
	aspect-ratio: 330 / 66;
	background-repeat: no-repeat;
}

.link-list {
	column-gap: 20px;
}

.link {
	position: relative;
	overflow: visible;
}

/* fleur for links */
.link:after {
	content: "";
	background: url(https://i.imgur.com/gDkXXh8.png) center/contain no-repeat;
	aspect-ratio: 114 / 163;
	display: block;
	position: absolute;
	width: 80px;
    left: 50%;
    transform: translateX(-50%) translateY(-50%);
    top: 50%;
}

@media (max-height: 900px) {
    .link:after {
        width: 64px;
    }
}

.link-group.in-folder .link-list {
	padding-block: 50px;
}

#link-mini {
	padding-top: 3em
}

#quotes_container {
	width: 63vw;
	max-width: unset;
} 

/* pomodoro */
#focus-toggle .trn {
    visibility: hidden;
    position: relative;
}

#focus-toggle .trn:after {
    visibility: visible;
    position: absolute;
    top: 0;
    left: 0;
    content: "Bind";
}

#notes_container {
	position: relative;
}

#pocket-editor {
    padding: 1.5em;
}

/* top notes fleur */
#notes_container:before {
    width: clamp(200px, 40vw, 400px);
    aspect-ratio: 79 / 10;
    background: url(https://i.imgur.com/4Bja4E1.png);
    top: -1.35rem;
}

/* bottom notes fleur */
#notes_container:after {
    width: clamp(100px, 30vw, 300px);
    aspect-ratio: 417 / 34;
    background: url(https://i.imgur.com/BnbjKyH.png);
    bottom: -0.75rem;
}

#notes_container:before, #notes_container:after {
    content: "";
    display: block;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1;
}

/* dark background that would be blur */
#pocket-editor, #searchbar-wrapper, #sb-suggestions, #linkblocks .link-folder .link-icon, #linkblocks.backgrounds .link-folder .link-icon, .link-group.in-folder .link-list, dialog {
    border: 0px;
    backdrop-filter: unset;
    box-shadow: unset;
    background-color: #000000b3;
}

/* square blur */
#pocket-editor, #searchbar-wrapper, #sb-suggestions, .link-group.in-folder .link-list, dialog {
    border-radius: 1px;
            /* blurry edges */
    -webkit-mask-image:
        linear-gradient(to top,    transparent, black 3px),
        linear-gradient(to bottom, transparent, black 3px),
        linear-gradient(to left,   transparent, black 3px),
        linear-gradient(to right,  transparent, black 3px);
    mask-image:
        linear-gradient(to top,    transparent, black 3px),
        linear-gradient(to bottom, transparent, black 3px),
        linear-gradient(to left,   transparent, black 3px),
        linear-gradient(to right,  transparent, black 3px);

    mask-composite: intersect;
    -webkit-mask-composite: source-in;
}

/* round blur (links) */
#linkblocks .link-folder .link-icon, #linkblocks.backgrounds .link-folder .link-icon {
    mask-image: radial-gradient(
        closest-side,
        black calc(100% - 3px),
        transparent
    );

    -webkit-mask-image: radial-gradient(
        closest-side,
        black calc(100% - 3px),
        transparent
    );

}

/* adds logo to the searchbar */
#searchbar {
  background: url(https://i.imgur.com/gMKSMMa.png) no-repeat 15px center;
  background-size: 23px;
  padding-left: 47px;
}

#sb_container {
    box-shadow: unset;
    border-radius: unset;
}

#searchbar-wrapper {
    padding: 5px;
}

/* credits */
#made-in:after {
    content: "— Silksong theme by Tahoe —\A"
    "Silksong and all related artwork belong to Team Cherry.";
    white-space: pre-line;
    display: block;
    margin-top: 10px;
    font-weight: bold;
}
